def test_bare_except_swallows_name_error():
    parts = "123:100".split(':')
    item_id = parts[0]
    amount = int(parts[1])

    try:
        total = amount + calculate_tax(amount)
    except NameError:
        raise AssertionError("NameError should be caught and exposed by the specific exception handling")
    else:
        assert total is None, "The function should raise a NameError due to missing 'calculate_tax' function"
